class LUPrefix {
    int n;
    int lastUploaded;
    boolean[] uploaded;

    public LUPrefix(int n) {
        this.n = n;
        this.lastUploaded = 0;
        this.uploaded = new boolean[n + 1];
    }

    public void upload(int video) {
        uploaded[video] = true;
        lastUploaded = Math.max(lastUploaded, video);
    }

    public int longest() {
        for (int i = 1; i <= lastUploaded; i++) {
            if (!uploaded[i]) {
                return i - 1;
            }
        }
        return lastUploaded;
    }
}
```
